export default function EmotionCard({ emotion, confidence }: any) {

    const color =
        emotion === "Negative"
        ? "text-red-500"
        : emotion === "Positive"
        ? "text-green-600"
        : "text-gray-600";

    return (
        <div className="bg-green-50 p-4 rounded-xl mt-4">

        <h3 className="font-semibold">Emotion</h3>

        <p className={`text-xl font-bold ${color}`}>
            {emotion}
        </p>

        <p>Confidence: {(confidence * 100).toFixed(2)}%</p>

        {emotion === "Negative" && (
            <p className="text-red-600 mt-2">
            ⚠️ Patient needs attention
            </p>
        )}

        </div>
    );
}